1	// Multi-variant roof analyser. Runs analyze-roof.ts under several preset
2	// parameter sets in parallel, then picks the result whose panel coverage looks
3	// physically most plausible.
4	//
5	// Run: pnpm bake:analyze:multi [houseId]
6	//
7	// Each variant is a child process that writes to a suffixed file, e.g.
8	// public/baked/{house}-analysis-A.json. We score each result, pick the
9	// winner, and copy it to public/baked/{house}-analysis.json (the canonical
10	// path Dev A and Dev B consume).
11	//
12	// Scoring heuristic (no Solar API in prod): "coverage" = panelArea / faceArea.
13	// The industry typical residential install lands around 30-45 % coverage, so
14	// we score variants by how close their coverage is to 0.40, with hard
15	// penalties for impossible (>0.95) or implausibly low (<0.10) values.
16	
17	import { promises as fs } from 'node:fs';
18	import path from 'node:path';
19	import { spawn } from 'node:child_process';
