332	// Convert LOD2 RoofSurface (from lod2-buildings.ts) → RoofFace expected by
333	// place-panels.ts. Vertices are already in local ENU meters around (lat, lng).
334	function lod2ToRoofFace(rs: LOD2RoofSurface, id: number): RoofFace {
335	  return {
336	    id,
337	    normal: rs.normal,
338	    area: rs.area,
339	    usableArea: rs.area,             // LOD2 doesn't carry obstructions; treat full area
340	    azimuth: rs.azimuth,
341	    tilt: rs.tilt,
342	    vertices: rs.polygon.map(([x, y, z]) => [x, y, z] as number[]),
343	    yieldKwhPerSqm: 1100,            // baseline DE residential — tilt/azimuth refinement
344	                                     // would only matter for downstream display
345	  };
346	}
