348	// Tries to fetch official cadastral LOD2 data and place panels on its
349	// RoofSurfaces. Returns null if no LOD2 data available for this Land or
350	// if no usable roof was found.
351	async function tryLod2Fallback(
352	  houseId: string,
353	  lat: number,
354	  lng: number,
355	): Promise<{ faces: RoofFace[]; modulePositions: { x: number; y: number; z: number; faceId: number }[]; source: string } | null> {
356	  const lod2 = await fetchLOD2Building(lat, lng, houseId);
357	  if (!lod2 || lod2.roofSurfaces.length === 0) return null;
358	  const faces = lod2.roofSurfaces.map((rs, i) => lod2ToRoofFace(rs, i));
359	  const obstructions: Obstruction[] = []; // LOD2 doesn't carry chimneys
360	  const modulePositions = faces.flatMap((f) => placePanelsOnFace(f, obstructions));
361	  return { faces, modulePositions, source: lod2.source };
362	}
