364	// Detects whether the picked variant's result is "aberrant" — a sign that
365	// the OSM/MS polygon source is fundamentally wrong or the mesh is missing
366	// the building. Used to trigger a LOD2 (cadastral) fallback when available.
367	//
368	// Only 4 criteria; C5 (variance) was tested but produced false positives on
369	// wins. With C1-C4, ALL 6 working cases (Köln1, Berlin1/2, Hamburg2,
370	// brandenburg, Dresden2) stay clean while Köln2, Leipzig, Dresden1 trigger.
371	// Meerbusch (-72%) and Bochum (-36%) are NOT detected — accepted as the
372	// price for zero false positives.
373	function isAberrant(
374	  picked: Scored,
375	  _scored: Scored[],
376	  plausibleCount: number,
377	): { aberrant: boolean; reason: string } {
378	  if (picked.coverage > 0.85) {
379	    return { aberrant: true, reason: `C1: picked coverage ${(picked.coverage * 100).toFixed(0)}% > 85% (over-stacking)` };
380	  }
381	  if (picked.faceArea > 400) {
382	    return { aberrant: true, reason: `C2: picked faceArea ${picked.faceArea.toFixed(0)} m² > 400 (likely multiple buildings)` };
383	  }
384	  if (picked.faceArea < 30) {
385	    return { aberrant: true, reason: `C3: picked faceArea ${picked.faceArea.toFixed(0)} m² < 30 (polygon/mesh missing)` };
386	  }
387	  if (plausibleCount === 0) {
388	    return { aberrant: true, reason: `C4: 0 plausible variants (cov ∈ [25%, 65%])` };
389	  }
390	  return { aberrant: false, reason: '' };
391	}
