393	function scoreVariant(data: AnalysisData): Pick<Scored, 'panelCount' | 'panelArea' | 'faceArea' | 'coverage' | 'score' | 'reason'> {
394	  const panelCount = data.modulePositions?.length ?? 0;
395	  const faceArea = data.faces.reduce((s, f) => s + f.area, 0);
396	  const panelArea = panelCount * PANEL_AREA;
397	  const coverage = faceArea > 0 ? panelArea / faceArea : 0;
398	
399	  // Hard penalties for unphysical outcomes.
400	  if (faceArea < 1) return { panelCount, panelArea, faceArea, coverage, score: 0, reason: 'no roof' };
401	  if (coverage > 0.95) return { panelCount, panelArea, faceArea, coverage, score: 0.05, reason: 'over-stacked (>95%)' };
402	  if (coverage < 0.10) return { panelCount, panelArea, faceArea, coverage, score: 0.10, reason: 'starved (<10%)' };
403	
404	  // Smooth peak at 40% coverage. Score is in (0, 1].
405	  const score = 1 / (1 + 5 * Math.abs(coverage - 0.40));
406	  const reason =
407	    coverage > 0.55 ? 'over-placement' : coverage < 0.25 ? 'under-placement' : 'on target';
408	  return { panelCount, panelArea, faceArea, coverage, score, reason };
409	}
