420	/** Read (lat, lng) from the photogrammetry header — needed to query LOD2. */
421	async function readHouseCoords(houseId: string): Promise<{ lat: number; lng: number } | null> {
422	  try {
423	    const photoPath = path.join(BAKED_DIR, `${houseId}-photogrammetry.json`);
424	    // Stream just the head of the file (a few KB is enough to capture
425	    // {"houseId":"...","lat":..,"lng":..,...). Avoids loading 10s of MB
426	    // of geometry just to read 2 numbers.
427	    const buf = Buffer.alloc(512);
428	    const fd = await fs.open(photoPath, 'r');
429	    try { await fd.read(buf, 0, 512, 0); } finally { await fd.close(); }
430	    const head = buf.toString('utf-8');
431	    const latMatch = head.match(/"lat"\s*:\s*([-\d.]+)/);
432	    const lngMatch = head.match(/"lng"\s*:\s*([-\d.]+)/);
433	    if (!latMatch || !lngMatch) return null;
434	    return { lat: parseFloat(latMatch[1]), lng: parseFloat(lngMatch[1]) };
435	  } catch {
436	    return null;
437	  }
438	}
