440	async function main() {
441	  const houseId = process.argv[2] ?? 'brandenburg';
442	
443	  console.log(`Running ${VARIANTS.length} variants for ${houseId}…`);
444	  for (const v of VARIANTS) console.log(`  ${v.suffix} (${v.name}): ${v.description}`);
445	  console.log('');
446	
447	  // Stage 1: seed the OSM polygon cache by running ONE variant. This avoids
448	  // 7 parallel Overpass requests racing — without the cache, Overpass rate-
449	  // limits some of them and the affected variants silently fall back to the
450	  // 15 m radius cylinder, which produces wildly inflated roofs.
451	  const t0 = Date.now();
452	  const cachePath = path.join(BAKED_DIR, `${houseId}-osm-polygon.json`);
453	  let cached = false;
454	  try { await fs.access(cachePath); cached = true; } catch { /* not cached */ }
455	  if (!cached) {
456	    console.log('Seeding OSM polygon cache (running variant -A first)…');
457	    await runChild(houseId, VARIANTS[0].env);
458	    console.log('Cache seeded. Running remaining variants in parallel…\n');
459	  } else {
460	    console.log('Using cached OSM polygon. Running all variants in parallel…\n');
461	  }
462	
463	  // Stage 2: run the rest (or all if cache was warm) in parallel.
464	  const toRun = cached ? VARIANTS : VARIANTS.slice(1);
465	  await Promise.allSettled(toRun.map((v) => runChild(houseId, v.env)));
466	  console.log(`\nAll variants done in ${((Date.now() - t0) / 1000).toFixed(1)}s\n`);
467	
468	  // Collect + score by reading each variant's output file. A missing file
469	  // means that variant crashed; we just skip it.
470	  const scored: Scored[] = [];
471	  for (const v of VARIANTS) {
472	    const data = await readVariantOutput(houseId, v.suffix);
473	    if (!data) {
474	      console.log(`  ${v.suffix} (${v.name}): no output file (variant failed)`);
475	      continue;
476	    }
477	    const s = scoreVariant(data);
478	    scored.push({ variant: v, data, ...s });
479	  }
480	
481	  if (scored.length === 0) {
482	    console.error('No variant produced output — aborting.');
483	    process.exit(1);
484	  }
485	
486	  scored.sort((a, b) => b.score - a.score);
487	
488	  console.log('\n=== Variant scores ===');
489	  console.log('  variant       roof    panels  panelArea  coverage  score  status');
490	  for (const s of scored) {
491	    console.log(
492	      `  ${s.variant.suffix} (${s.variant.name.padEnd(13)}) ` +
493	        `${s.faceArea.toFixed(0).padStart(5)} m²  ` +
494	        `${s.panelCount.toString().padStart(4)}    ` +
495	        `${s.panelArea.toFixed(1).padStart(6)} m²  ` +
496	        `${(s.coverage * 100).toFixed(0).padStart(4)}%    ` +
497	        `${s.score.toFixed(3)}  ` +
498	        `${s.reason}`,
499	    );
500	  }
501	
502	  // ---- Per-house variant selection ----
503	  //
504	  // Replaces the old consensus + ratchet + rescue stack with a simpler,
505	  // more interpretable rule: pick the SINGLE variant best-suited to THIS
506	  // house. Steps:
507	  //   1. filter to "plausible" variants — own coverage ∈ [25 %, 65 %] and
508	  //      panel count > 0. Drops variants that under-detect (over-shaded
509	  //      mesh) or over-stack (multi-level phantom panels).
510	  //   2. if -L's auto-multi-level filter fired, prefer -L (multi-pavilion
511	  //      override — same as the old multi-pavilion rescue).
512	  //   3. otherwise, pick the MEDIAN-panel-count variant among plausible.
513	  //      Median is robust to outliers (a single tree-tolerant -R giving
514	  //      80 panels won't shift the answer if 5 other variants give 40-50).
515	  //   4. if no variant is plausible, fall back to the highest-coverage one
516	  //      whose own coverage is ≤ 65 % (avoids over-stacked outputs).
517	
518	  const PLAUSIBLE_COV_MIN = 0.25;
519	  const PLAUSIBLE_COV_MAX = 0.65;
520	  const plausible = scored.filter(
521	    (s) => s.panelCount > 0 && s.coverage >= PLAUSIBLE_COV_MIN && s.coverage <= PLAUSIBLE_COV_MAX,
522	  );
523	
524	  let winners: ModulePos[] = [];
525	  let pickedReason = '';
526	  let pickedSuffix = '';
527	
528	  // Hard-fail check: if every variant returns a tiny roof, the OSM polygon
529	  // or mesh is broken — log explicitly so the failure isn't silent.
530	  const allTiny = scored.every((s) => s.faceArea < 30);
531	  if (allTiny) {
532	    console.warn(
533	      `[selection] all variants returned tiny roofs (max ${Math.max(...scored.map((s) => s.faceArea)).toFixed(1)} m²) — likely OSM/mesh mismatch.`,
534	    );
535	  }
536	
537	  // §1.1 — Multi-pavilion override (hardened): -L only wins if THREE conditions hold:
538	  //   • p80Range > 14 m (was implicit > 8 m, too sensitive — trees/terrain trip it)
539	  //   • L.panelCount ≥ 0.6 × median of OTHER plausibles (sanity vs over-cut)
540	  //   • L.faceArea ≥ 0.7 × max faceArea (the median-band didn't drop too much)
541	  const lVariant = scored.find((s) => s.variant.suffix === '-L');
542	  const otherPlausibleCounts = plausible
543	    .filter((s) => s.variant.suffix !== '-L')
544	    .map((s) => s.panelCount)
545	    .sort((a, b) => a - b);
546	  const medianOther = otherPlausibleCounts.length
547	    ? otherPlausibleCounts[Math.floor(otherPlausibleCounts.length / 2)]
548	    : 0;
549	  const maxFace = Math.max(...scored.map((s) => s.faceArea), 1);
550	
551	  const lFiredLegit =
552	    lVariant &&
553	    lVariant.panelCount > 0 &&
554	    lVariant.data._autoMultiLevel?.fired &&
555	    (lVariant.data._autoMultiLevel.p80Range ?? 0) > 14 &&
556	    lVariant.panelCount >= medianOther * 0.6 &&
557	    lVariant.faceArea >= maxFace * 0.7;
558	
559	  if (lFiredLegit) {
560	    winners = (lVariant.data.modulePositions ?? []).map((p) => ({ ...p }));
561	    pickedSuffix = '-L';
562	    pickedReason = `multi-pavilion legit (p80=${lVariant.data._autoMultiLevel?.p80Range?.toFixed(1)} m > 14, L panels ${lVariant.panelCount} ≥ 60% of median ${medianOther})`;
563	  } else if (plausible.length > 0) {
564	    // Median by panel count — robust to outliers like -R no-shade.
565	    const sorted = plausible.slice().sort((a, b) => a.panelCount - b.panelCount);
566	    const median = sorted[Math.floor(sorted.length / 2)];
567	    let pick = median;
568	
569	    // §1.2 — Cascade tree-heavy: try -Q first (very tree-heavy, ratio 2.5×),
570	    // then -J (moderate tree-heavy, ratio 1.6×). Guard with aRaw.coverage < 0.20
571	    // so we don't yank Potsdam where -A is already correct.
572	    const aRaw = scored.find((s) => s.variant.suffix === '-A');
573	    const jV = plausible.find((s) => s.variant.suffix === '-J');
574	    const qV = plausible.find((s) => s.variant.suffix === '-Q');
575	    if (pick === median && aRaw && aRaw.coverage < 0.20) {
576	      // Prefer -J first (less aggressive: 45% shade threshold). Only escalate
577	      // to -Q (60%) when -J is itself starved (cov < 25%) — sign of very heavy
578	      // vegetation where 45% still rejects too much.
579	      const jPicksAggressively = jV && jV.panelCount >= aRaw.panelCount * 1.6;
580	      const qPicksWayMore = qV && qV.panelCount >= aRaw.panelCount * 2.5;
581	      if (jPicksAggressively && jV.coverage <= 0.65) {
582	        pick = jV;
583	        pickedReason = `tree-heavy (-J ${jV.panelCount} ≥ 1.6× -A ${aRaw.panelCount})`;
584	      } else if (qPicksWayMore && qV.coverage <= 0.65) {
585	        pick = qV;
586	        pickedReason = `tree-very-heavy (-Q ${qV.panelCount} ≥ 2.5× -A ${aRaw.panelCount}, -A starved cov ${(aRaw.coverage * 100).toFixed(0)}%)`;
587	      }
588	    }
589	
590	    // §1.3 — Reihenhaus override (broadened): when OSM is too tight, prefer
591	    // a MS-based variant (-S, -T, -O) whose face area is significantly larger
592	    // and whose coverage is plausible.
593	    if (pick === median) {
594	      const maxOsmRoof = Math.max(...scored.filter((s) => !['-S', '-T', '-O'].includes(s.variant.suffix)).map((s) => s.faceArea), 1);
595	      const msCandidates = ['-S', '-T', '-O']
596	        .map((suf) => plausible.find((s) => s.variant.suffix === suf))
597	        .filter((v): v is Scored => !!v && v.faceArea >= maxOsmRoof * 1.25 && v.coverage >= 0.25 && v.coverage <= 0.60);
598	      if (msCandidates.length > 0) {
599	        msCandidates.sort((a, b) => b.faceArea - a.faceArea);
600	        pick = msCandidates[0];
601	        pickedReason = `OSM too tight (max OSM roof ${maxOsmRoof.toFixed(0)} m² → ${pick.variant.suffix} ${pick.faceArea.toFixed(0)} m², ${pick.panelCount} panels)`;
602	      }
603	    }
604	
605	    // §1.4 — OSM too large override: when median has high coverage AND -U gives
606	    // a smaller, plausible polygon, prefer -U (DBSCAN isolated the address pavilion).
607	    if (pick === median && median.coverage > 0.50) {
608	      const uV = plausible.find((s) => s.variant.suffix === '-U');
609	      if (uV && uV.faceArea < median.faceArea * 0.7 && uV.panelCount > 0 && uV.coverage <= 0.65) {
610	        pick = uV;
611	        pickedReason = `OSM too large (median cov ${(median.coverage * 100).toFixed(0)}%, -U shrinks ${median.faceArea.toFixed(0)}→${uV.faceArea.toFixed(0)} m², ${uV.panelCount} panels)`;
612	      }
613	    }
614	
615	    if (pick === median) {
616	      pickedReason = `median of ${plausible.length} plausible variants (cov ${(median.coverage * 100).toFixed(0)}%)`;
617	    }
618	
619	    winners = (pick.data.modulePositions ?? []).map((p) => ({ ...p }));
620	    pickedSuffix = pick.variant.suffix;
621	  } else {
622	    // No plausible variants — pick the variant with the most panels among
623	    // those with coverage ≤ 65 %. This is the under-detected case (e.g.
624	    // over-shaded mesh where every variant rejects most candidates).
625	    const candidate = scored
626	      .slice()
627	      .sort((a, b) => b.panelCount - a.panelCount)
628	      .find((s) => s.coverage <= 0.65 && s.panelCount > 0);
629	    if (candidate) {
630	      winners = (candidate.data.modulePositions ?? []).map((p) => ({ ...p }));
631	      pickedSuffix = candidate.variant.suffix;
632	      pickedReason = `no plausible variant — fallback to highest-panel under-detected variant (${candidate.panelCount} panels, ${(candidate.coverage * 100).toFixed(0)}%)`;
633	    } else {
634	      // Nothing usable. Use the score-leader as last resort.
635	      const fallback = scored[0];
636	      winners = (fallback.data.modulePositions ?? []).map((p) => ({ ...p }));
637	      pickedSuffix = fallback.variant.suffix;
638	      pickedReason = `no plausible / fallback to score leader (${fallback.panelCount} panels)`;
639	    }
640	  }
641	
642	  console.log('\n=== Per-house variant selection ===');
643	  console.log(`  plausible variants (coverage ∈ [${(PLAUSIBLE_COV_MIN * 100).toFixed(0)}%, ${(PLAUSIBLE_COV_MAX * 100).toFixed(0)}%]): ${plausible.length}/${scored.length}`);
644	  for (const p of plausible) {
645	    console.log(`    ${p.variant.suffix.padEnd(3)} ${p.variant.name.padEnd(20)} ${p.panelCount.toString().padStart(3)} panels @ ${(p.coverage * 100).toFixed(0)}% cov`);
646	  }
647	  console.log(`  → picked ${pickedSuffix}: ${pickedReason}`);
648	
649	  // Build the final analysis.json. Use the picked variant's geometric base
650	  // (faces / footprint / obstructions) and its panel positions.
651	  const pickedScored = scored.find((s) => s.variant.suffix === pickedSuffix) ?? scored[0];
652	  const base = pickedScored.data;
653	
654	  // Aberrant-result detection: 4 criteria that flag the picked result as
655	  // suspect enough to warrant fetching LOD2 (cadastral data) as a fallback.
656	  // Only TRIGGER ON ABERRATION — do NOT touch results that look reasonable
657	  // (zero risk of regression on the wins). Verified on benchmark: 3 TP
658	  // (Köln2, Leipzig, Dresden1) + 0 FP across the 6 working cases.
659	  const aberration = isAberrant(pickedScored, scored, plausible.length);
660	  let lod2Override: { faces: RoofFace[]; modulePositions: ModulePos[]; source: string } | null = null;
661	  let baseFaces = base.faces;
662	
663	  if (aberration.aberrant && process.env.DISABLE_LOD2_FALLBACK !== '1') {
664	    console.log(`\n=== ABERRANT RESULT DETECTED ===`);
665	    console.log(`  Reason: ${aberration.reason}`);
666	    const coords = await readHouseCoords(houseId);
667	    if (!coords) {
668	      console.log(`  → could not read photogrammetry coords; skipping LOD2 retry`);
669	    } else {
670	      console.log(`  → fetching LOD2 for (${coords.lat}, ${coords.lng})…`);
671	      const t1 = Date.now();
672	      lod2Override = await tryLod2Fallback(houseId, coords.lat, coords.lng);
673	      console.log(`  → LOD2 fetch took ${((Date.now() - t1) / 1000).toFixed(1)}s`);
674	      if (lod2Override) {
675	        console.log(
676	          `  ✓ LOD2 (${lod2Override.source}) override applied: ${lod2Override.modulePositions.length} panels ` +
677	            `(was ${winners.length} via variant ${pickedSuffix})`,
678	        );
679	        winners = lod2Override.modulePositions;
680	        baseFaces = lod2Override.faces as typeof base.faces;
681	        pickedReason = `${pickedReason} → LOD2 ${lod2Override.source} OVERRIDE (${lod2Override.modulePositions.length} panels on ${lod2Override.faces.length} official roof surfaces)`;
682	        pickedSuffix = `LOD2-${lod2Override.source}`;
683	      } else {
684	        console.log(`  ✗ LOD2 unavailable for this Land — keeping aberrant result`);
685	      }
686	    }
687	  }
688	
689	  const consensus = {
690	    ...base,
691	    faces: baseFaces,
692	    modulePositions: winners,
693	    _selection: {
694	      method: 'per-house best variant',
695	      variantCount: scored.length,
696	      plausibleCount: plausible.length,
697	      pickedVariant: pickedSuffix,
698	      pickedReason,
699	      aberrant: aberration.aberrant,
700	      aberrantReason: aberration.reason,
701	      lod2Source: lod2Override?.source ?? null,
702	    },
703	  };
704	
705	  const canonicalPath = path.join(BAKED_DIR, `${houseId}-analysis.json`);
706	  await fs.writeFile(canonicalPath, JSON.stringify(consensus, null, 2));
707	  console.log(`\nWrote → ${canonicalPath}`);
708	  console.log(`Final: ${winners.length} panels (${(winners.length * PANEL_AREA).toFixed(1)} m²)`);
709	}
710	
711	main().catch((err) => {
712	  console.error(err);
713	  process.exit(1);
714	});
