153	/** Keep only triangles within `band` of the local-max Y in their XZ cell. */
154	function topLevelFilter(tris: Triangle[], cellSize: number, band: number): Triangle[] {
155	  const cells = new Map<string, number>();
156	  for (const t of tris) {
157	    const cx = Math.floor(t.centroid[0] / cellSize);
158	    const cz = Math.floor(t.centroid[2] / cellSize);
159	    const key = `${cx}|${cz}`;
160	    const cur = cells.get(key) ?? -Infinity;
161	    if (t.centroid[1] > cur) cells.set(key, t.centroid[1]);
162	  }
163	  return tris.filter((t) => {
164	    const cx = Math.floor(t.centroid[0] / cellSize);
165	    const cz = Math.floor(t.centroid[2] / cellSize);
166	    return t.centroid[1] >= (cells.get(`${cx}|${cz}`) ?? 0) - band;
167	  });
168	}
169	
170	/** Keep only the Y-band cluster (1 m bands) with the largest summed area. */
171	function dominantLevelFilter(tris: Triangle[], bandM = 1.0): Triangle[] {
172	  if (tris.length === 0) return tris;
173	  let minY = Infinity;
174	  let maxY = -Infinity;
175	  for (const t of tris) {
176	    if (t.centroid[1] < minY) minY = t.centroid[1];
177	    if (t.centroid[1] > maxY) maxY = t.centroid[1];
178	  }
179	  const nBands = Math.max(1, Math.ceil((maxY - minY) / bandM));
180	  const bands: { tris: Triangle[]; area: number }[] = Array.from({ length: nBands }, () => ({ tris: [], area: 0 }));
181	  for (const t of tris) {
182	    const idx = Math.min(nBands - 1, Math.max(0, Math.floor((t.centroid[1] - minY) / bandM)));
183	    bands[idx].tris.push(t);
184	    bands[idx].area += t.area;
185	  }
186	  // Find the band with max area, then expand to include adjacent bands within
187	  // 50 % of its area (handles a roof split across two bands by ridge height).
188	  let bestIdx = 0;
189	  for (let i = 1; i < bands.length; i++) if (bands[i].area > bands[bestIdx].area) bestIdx = i;
190	  const bestArea = bands[bestIdx].area;
191	  const out: Triangle[] = [];
192	  for (let i = 0; i < bands.length; i++) {
193	    if (i === bestIdx || (Math.abs(i - bestIdx) <= 2 && bands[i].area > bestArea * 0.5)) {
194	      out.push(...bands[i].tris);
195	    }
196	  }
197	  return out;
198	}
