252	function buildTrianglesFromArrays(positions: ArrayLike<number>, indices: ArrayLike<number>): Triangle[] {
253	  const triangles: Triangle[] = [];
254	  const triCount = indices.length / 3;
255	  for (let t = 0; t < triCount; t++) {
256	    const i0 = indices[t * 3];
257	    const i1 = indices[t * 3 + 1];
258	    const i2 = indices[t * 3 + 2];
259	
260	    const v0: [number, number, number] = [positions[i0 * 3], positions[i0 * 3 + 1], positions[i0 * 3 + 2]];
261	    const v1: [number, number, number] = [positions[i1 * 3], positions[i1 * 3 + 1], positions[i1 * 3 + 2]];
262	    const v2: [number, number, number] = [positions[i2 * 3], positions[i2 * 3 + 1], positions[i2 * 3 + 2]];
263	
264	    const ax = v1[0] - v0[0];
265	    const ay = v1[1] - v0[1];
266	    const az = v1[2] - v0[2];
267	    const bx = v2[0] - v0[0];
268	    const by = v2[1] - v0[1];
269	    const bz = v2[2] - v0[2];
270	
271	    const cx = ay * bz - az * by;
272	    const cy = az * bx - ax * bz;
273	    const cz = ax * by - ay * bx;
274	    const len = Math.hypot(cx, cy, cz);
275	    if (len < 1e-8) continue;
276	
277	    const area = len * 0.5;
278	    const normal: [number, number, number] = [cx / len, cy / len, cz / len];
279	    const centroid: [number, number, number] = [
280	      (v0[0] + v1[0] + v2[0]) / 3,
281	      (v0[1] + v1[1] + v2[1]) / 3,
282	      (v0[2] + v1[2] + v2[2]) / 3,
283	    ];
284	    triangles.push({ centroid, normal, area, vertices: [v0, v1, v2] });
285	  }
286	  return triangles;
287	}
