475	function convexHullXZ(points: [number, number, number][]): [number, number, number][] {
476	  // Andrew's monotone chain in the XZ plane — preserves each vertex's original
477	  // Y so a tilted roof face keeps its 3D shape (place-panels.ts needs the real
478	  // Y to build a non-degenerate face frame).
479	  if (points.length < 3) return points;
480	  const sorted = [...points].sort((a, b) => (a[0] === b[0] ? a[2] - b[2] : a[0] - b[0]));
481	
482	  const cross = (o: number[], a: number[], b: number[]) =>
483	    (a[0] - o[0]) * (b[2] - o[2]) - (a[2] - o[2]) * (b[0] - o[0]);
484	
485	  const lower: [number, number, number][] = [];
486	  for (const p of sorted) {
487	    while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], p) <= 0) lower.pop();
488	    lower.push(p);
489	  }
490	  const upper: [number, number, number][] = [];
491	  for (let i = sorted.length - 1; i >= 0; i--) {
492	    const p = sorted[i];
493	    while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], p) <= 0) upper.pop();
494	    upper.push(p);
495	  }
496	  return [...lower.slice(0, -1), ...upper.slice(0, -1)];
497	}
