  const validRoof = data.filter(d=>d.fa>=20).map(d=>d.fa).sort((a,b)=>a-b);
  const medRoof = validRoof[Math.floor(validRoof.length/2)] || 0;
  // Target = medRoof * 0.55 / 1.96
  const target = medRoof * 0.55 / 1.964;
  // Pick variant with panels closest to target AND cov ∈ [0.30, 0.65]
  const candidates = data.filter(d=>d.cov >= 0.30 && d.cov <= 0.65 && d.panels > 0);
