      const sorted2 = plausible.slice().sort((a,b)=>a.panelCount - b.panelCount);
      pick = sorted2[Math.floor(sorted2.length/2)] || pick;
      reason = 'median (tree-heavy capped)';
    }
  }

  // Polygon-mismatch detection: picked face area is a small fraction of the
  // median face area across plausible variants → polygon source likely wrong.
  if (options.polyMismatchFlag && plausible.length >= 2) {
    const allFaces = scored.filter(s => s.panelCount > 0).map(s => s.faceArea).sort((a,b)=>a-b);
    const medianFA = allFaces[Math.floor(allFaces.length/2)];
    if (medianFA > 0 && pick.faceArea < medianFA * 0.5) {
      // We can't run LOD2 in sim. Just flag for now.
      reason = `${reason}|POLY-MISMATCH(picked ${pick.faceArea.toFixed(0)} < 0.5*median ${medianFA.toFixed(0)})`;
    }
  }

  return { ...pick, pickedReason: reason };
}

function summarize(rows) {
  let total = 0, w10 = 0, w25 = 0;
  for (const r of rows) {
    total += Math.abs(r.delta);
    if (Math.abs(r.delta) <= 10) w10++;
    if (Math.abs(r.delta) <= 25) w25++;
  }
  return { mean: total/rows.length, w10, w25 };
}

function run(label, options = {}) {
  console.log(`\n===== ${label} =====`);
  const rows = [];
  let regressedWins = [];
  for (const [house, gt] of Object.entries(GT)) {
    const scored = [];
    for (const v of VARIANTS) {
      const data = loadVariant(house, v);
      if (!data) continue;
      const sc = scoreVariant(data);
      scored.push({ suffix: v, ...sc, data });
    }
    if (scored.length === 0) continue;
    const pick = pickVariant(scored, options);
    const delta = ((pick.panelCount - gt) / gt) * 100;
    rows.push({ house, gt, picked: pick.suffix || '?', panels: pick.panelCount, delta, reason: pick.pickedReason || 'none', isWin: WINS.has(house) });
    // Detect regression on wins (was within ±10%)
    if (WINS.has(house) && Math.abs(delta) > 10) regressedWins.push(`${house}: Δ${delta.toFixed(0)}%`);
  }
  rows.sort((a,b)=>Math.abs(a.delta)-Math.abs(b.delta));
  for (const r of rows) {
    const flag = r.isWin ? ' [WIN]' : '';
    console.log(`  ${r.house.padEnd(20)} gt=${r.gt.toString().padStart(2)} pick=-${r.picked} (${r.reason.padEnd(20)}) panels=${r.panels.toString().padStart(3)} Δ=${(r.delta>=0?'+':'')+r.delta.toFixed(0)+'%'}${flag}`);
  }
  const s = summarize(rows);
  console.log(`\n  SUMMARY: mean|Δ|=${s.mean.toFixed(1)}%  ±10%=${s.w10}/${rows.length}  ±25%=${s.w25}/${rows.length}`);
  if (regressedWins.length > 0) console.log(`  REGRESSED WINS: ${regressedWins.join(', ')}`);
}

run('BASELINE (current logic)');
run('EXP: prefer-F when starved median', { preferFOnStarvedMedian: true });

