const VARIANTS = 'ABCDEFGHIJKLMNOPQRSTUV'.split('');
for (const h of ['bench-berlin1','bench-koeln1','bench-hamburg2','b3-zehlendorf','b3-wannsee','b3-karow','test2','b3-hermsdorf2','brandenburg','bench-dresden2','test1','test3','test4','b3-mahlsdorf2','b3-lichterfelde','bench-bochum']) {
