// floor(face.usableArea * cap / panelArea). Combined with flux-based
// ranking in place-panels.ts, keeps the BEST panels (highest annual flux)
// when the raw placement would over-stack. Targets multi-level / dormer
// roofs where the geometric grid produces phantom layers.
const PANEL_AREA_M2 = 1.045 * 1.879;
let rawPanels = faces.flatMap((face) => {
  let maxModules: number | undefined;
  if (VARIANT_PANEL_DENSITY_CAP > 0 && VARIANT_PANEL_DENSITY_CAP < 1.0) {
    const usable = face.usableArea ?? face.area;
    maxModules = Math.max(1, Math.floor((usable * VARIANT_PANEL_DENSITY_CAP) / PANEL_AREA_M2));
  }
  return placePanelsOnFace(face, obstructions, maxModules, shadeSampler ?? undefined);
});

