}
console.log('\\n=== STEP 2 (-W variant) SUMMARY ===');
console.log('Mean |Δ%|:', (totalAbs/count).toFixed(1));
console.log('±10%:', within10+'/'+count);
console.log('±25%:', within25+'/'+count);
"

