node -e "
const fs = require('fs');
const PA = 1.045 * 1.879;
const VARIANTS = 'ABCDEFGHIJKLMNOPQRSTUV'.split('');
const houses = ['bench-berlin1','bench-koeln1','bench-hamburg2','b3-zehlendorf','b3-wannsee','b3-karow','test2','bench-bochum','b3-mahlsdorf2','b3-lichterfelde','test1','test4','bench-berlin2','b3-mahlsdorf','b3-kladow','bench-dresden2','test3','b3-hermsdorf2','brandenburg'];
const gt = {'bench-berlin1':73,'bench-koeln1':26,'bench-hamburg2':59,'b3-zehlendorf':22,'b3-wannsee':53,'b3-karow':35,'test2':39,'bench-bochum':50,'b3-mahlsdorf2':40,'b3-lichterfelde':33,'test1':22,'test4':38,'bench-berlin2':40,'b3-mahlsdorf':87,'b3-kladow':35,'bench-dresden2':66,'test3':48,'b3-hermsdorf2':49,'brandenburg':48};
console.log('house              gt picked  -F  F-cov  F-fa  maxOsmExFP  ratio  rule-fire?  predicted-Δ');
for (const h of houses) {
  let picked = 0;
  try { const c = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis.json','utf-8')); picked = c.modulePositions?.length||0; } catch(e){}
  const data = [];
  for (const v of VARIANTS) {
    try {
      const a = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis-'+v+'.json','utf-8'));
      const fa = (a.faces||[]).reduce((s,f)=>s+f.area,0);
      const np = a.modulePositions?.length||0;
      data.push({v, fa, np, cov: fa>0?np*PA/fa:0});
    } catch(e){}
  }
  const f = data.find(d=>d.v==='F');
  if (!f) continue;
  // Calculate maxOsm excluding S/T/O/F/W
  const maxOsm = Math.max(...data.filter(d=>!['S','T','O','F','W'].includes(d.v)).map(d=>d.fa), 1);
  const fPlaus = f.np > 0 && f.cov >= 0.25 && f.cov <= 0.55;
  const fFires = fPlaus && f.fa >= maxOsm * 1.25;
  const predictedDelta = fFires ? ((f.np - gt[h])/gt[h]*100).toFixed(0)+'%' : '-';
  const currentDelta = ((picked - gt[h])/gt[h]*100).toFixed(0)+'%';
  console.log(h.padEnd(20), gt[h].toString().padStart(2), picked.toString().padStart(5), f.np.toString().padStart(3),
    f.cov.toFixed(2).padStart(5), f.fa.toFixed(0).padStart(4), maxOsm.toFixed(0).padStart(8), (f.fa/maxOsm).toFixed(2).padStart(5),
    (fFires?'FIRE':'no').padStart(8), '(curr',currentDelta+',', 'with-F:'+predictedDelta+')');
}
"

