const fs = require('fs');
const PA = 1.045 * 1.879;
const houses = ['bench-berlin1','bench-koeln1','bench-hamburg2','b3-zehlendorf','b3-wannsee','b3-karow','test2','bench-koeln2','bench-meerbusch','bench-leipzig','bench-dresden1','bench-dresden2','bench-bochum','b3-mahlsdorf','b3-mahlsdorf2','b3-kladow','b3-lichterfelde','b3-hermsdorf','b3-hermsdorf2','b3-wannsee2','test1','test3','test4','brandenburg','bench-berlin2'];
const gt = {'bench-berlin1':73,'bench-koeln1':26,'bench-hamburg2':59,'b3-zehlendorf':22,'b3-wannsee':53,'b3-karow':35,'test2':39,'bench-koeln2':37,'bench-meerbusch':57,'bench-leipzig':67,'bench-dresden1':39,'bench-dresden2':66,'bench-bochum':50,'b3-mahlsdorf':87,'b3-mahlsdorf2':40,'b3-kladow':35,'b3-lichterfelde':33,'b3-hermsdorf':10,'b3-hermsdorf2':49,'b3-wannsee2':26,'test1':22,'test3':48,'test4':38,'brandenburg':48,'bench-berlin2':40};
function sim(maxRatio) {
  let w10=0, w25=0, total=0;
  let regress=[];
  const rows=[];
  for (const h of houses) {
    const c = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis.json','utf-8'));
    const sel = c._selection || {};
    let np = c.modulePositions?.length||0;
    const fa = (c.faces||[]).reduce((s,f)=>s+f.area,0);
    let bnp=0,bfa=0,bcov=0;
    try { const a = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis-B.json','utf-8'));
      bnp = a.modulePositions?.length||0;
      bfa = (a.faces||[]).reduce((s,f)=>s+f.area,0);
      bcov = bfa>0 ? bnp*PA/bfa : 0;
    } catch(e){}
    const ratio = np>0 ? bnp/np : 0;
    const fares = bfa>0 && fa>0 ? bfa/fa : 0;
    const isMedian = (sel.pickedReason||'').includes('median') || (sel.pickedReason||'').includes('B-eaves');
    // Note: only fire if NOT already a tree-heavy/MS pick
    const fires = isMedian && bcov >= 0.45 && bcov <= 0.70 && ratio >= 1.10 && ratio <= maxRatio && fares >= 1.02 && sel.pickedVariant !== '-B';
    let final = np;
    if (fires) final = bnp;
    const delta = ((final - gt[h])/gt[h]*100);
    total += Math.abs(delta);
    if (Math.abs(delta) <= 10) w10++;
    if (Math.abs(delta) <= 25) w25++;
    rows.push({h, gt: gt[h], final, delta, fires});
  }
  return {w10, w25, mean: total/houses.length, rows};
}
for (const r of [1.30, 1.40, 1.50, 1.65, 1.80]) {
  const s = sim(r);
  console.log('maxRatio='+r, '±10:', s.w10+'/25', '±25:', s.w25+'/25', 'mean:', s.mean.toFixed(1));
  for (const row of s.rows) if (row.fires) console.log('  fires:', row.h, 'gt='+row.gt, '->', row.final, 'Δ='+row.delta.toFixed(0)+'%');
}
"

