  for (const v of VARIANTS) {
    if (v==='W') continue; // exclude W from plausibles
    try {
      const a = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis-'+v+'.json','utf-8'));
      const fa = (a.faces||[]).reduce((s,f)=>s+f.area,0);
      const np = a.modulePositions?.length||0;
      const cov = fa>0 ? np*PA/fa : 0;
      if (np > 0 && cov >= 0.25 && cov <= 0.65) plaus.push({v, np, fa, cov});
    } catch(e){}
  }
  // Use mean panel count
  if (plaus.length === 0) continue;
  const mean = plaus.reduce((s,p)=>s+p.np,0) / plaus.length;
  // Pick variant closest to mean
  plaus.sort((a,b)=>Math.abs(a.np - mean) - Math.abs(b.np - mean));
  const pick = plaus[0];
  const delta = ((pick.np - gt[h])/gt[h]*100);
  total += Math.abs(delta);
  if (Math.abs(delta) <= 10) w10++;
  if (Math.abs(delta) <= 25) w25++;
