const fs = require('fs');
const groundTruth = {'bench-berlin1':73,'bench-koeln1':26,'bench-hamburg2':59,'b3-zehlendorf':22,'b3-wannsee':53,'b3-karow':35,'test2':39,'bench-koeln2':37,'bench-meerbusch':57,'bench-leipzig':67,'bench-dresden1':39,'bench-bochum':50,'b3-mahlsdorf':87,'b3-mahlsdorf2':40,'b3-kladow':35,'b3-lichterfelde':33,'b3-hermsdorf':10,'b3-wannsee2':26,'test4':38,'bench-berlin2':40,'test1':22,'test3':48,'b3-hermsdorf2':49,'bench-dresden2':66,'brandenburg':48};
const wins = ['bench-berlin1','bench-koeln1','bench-hamburg2','b3-zehlendorf','b3-wannsee','b3-karow','test2'];
let w10=0, w25=0, total=0;
const rows=[];
for (const [house, gt] of Object.entries(groundTruth)) {
  const a = JSON.parse(fs.readFileSync('public/baked/'+house+'-analysis.json', 'utf-8'));
  const n = (a.modulePositions||[]).length;
  const delta = ((n - gt) / gt) * 100;
  rows.push({house, gt, algo: n, delta, isWin: wins.includes(house)});
  total += Math.abs(delta);
  if (Math.abs(delta) <= 10) w10++;
  if (Math.abs(delta) <= 25) w25++;
}
rows.sort((a,b)=>Math.abs(a.delta||0)-Math.abs(b.delta||0));
for (const r of rows) console.log((r.house+'              ').slice(0,22), 'gt='+r.gt, 'algo='+r.algo, 'Δ='+(r.delta>=0?'+':'')+r.delta.toFixed(0)+'%', r.isWin?'[WIN]':'');
console.log('\\nMean:', (total/25).toFixed(1), '±10:', w10+'/25', '±25:', w25+'/25');
"

