const fs = require('fs');
const PA = 1.045 * 1.879;
for (const h of ['bench-bochum','b3-mahlsdorf','b3-mahlsdorf2','bench-berlin2','test4']) {
  try {
    const a = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis-X.json','utf-8'));
    const fa = (a.faces||[]).reduce((s,f)=>s+f.area,0);
    const np = a.modulePositions?.length||0;
    console.log(h.padEnd(20), '-X', np, 'panels @', fa.toFixed(0)+'m² cov', (np*PA/fa).toFixed(2));
  } catch(e){console.log(h, 'no -X', e.message);}
}
"

