  const c = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis.json','utf-8'));
  const np = c.modulePositions?.length||0;
  const fa = (c.faces||[]).reduce((s,f)=>s+f.area,0);
  const cov = fa>0 ? np*PA/fa : 0;
  let xnp=0, xfa=0, xcov=0;
  try { const a = JSON.parse(fs.readFileSync('public/baked/'+h+'-analysis-X.json','utf-8'));
    xnp = a.modulePositions?.length||0;
    xfa = (a.faces||[]).reduce((s,f)=>s+f.area,0);
    xcov = xfa>0 ? xnp*PA/xfa : 0;
  } catch(e){}
  const ratio = np>0 ? xnp/np : 0;
  console.log(h.padEnd(20), 'pick='+np+' cov '+cov.toFixed(2), '|', '-X='+xnp+' cov '+xcov.toFixed(2), 'ratio='+ratio.toFixed(2));
}
"

