1	// Panel placement algorithm — OWNED by Dev D
2	// Given a roof face + obstructions + module size, return panel positions on a grid.
3	
4	import * as THREE from 'three';
5	import type { RoofFace, Obstruction } from '@/lib/types';
6	
7	// Industry-standard residential panel dimensions (Hanwha Q.Peak 400W class) —
8	// matches Google Solar API's reference panel for fair area comparisons.
9	// Env-overridable knobs (used by analyze-multi.ts variants).
10	const numEnv = (name: string, def: number): number => {
11	  const v = process.env[name];
12	  return v !== undefined && !Number.isNaN(parseFloat(v)) ? parseFloat(v) : def;
13	};
14	
15	const MODULE_WIDTH_M = 1.045;
16	const MODULE_HEIGHT_M = 1.879;
17	// Industry typical eaves/ridge offset is ~30-40 cm.
18	const EDGE_OFFSET_M = numEnv('VARIANT_EDGE_OFFSET_M', 0.3);
19	const MODULE_GAP_M = 0.02;
20	
21	interface ModulePosition {
22	  x: number;
23	  y: number;
24	  z: number;
25	  faceId: number;
26	}
27	
28	/**
29	 * Optional shade-aware filter. Given a candidate panel position in world
30	 * coords, returns the fraction of sample sun positions where this point is
31	 * blocked by the photogrammetry mesh (0 = always sunlit, 1 = always shaded).
32	 *
33	 * Optionally also estimates the annual direct-beam flux (kWh/m²/yr) for the
34	 * given panel position + normal — used by analyze-roof to drop panels whose
35	 * combined orientation + shading puts them below a yield threshold.
36	 */
37	export interface ShadeSampler {
38	  shadedFraction(x: number, y: number, z: number): number;
39	  annualFlux?(x: number, y: number, z: number, normal: [number, number, number]): number;
40	}
41	
42	const MAX_SHADED_FRACTION = numEnv('VARIANT_MAX_SHADED_FRACTION', 0.30);
43	
44	/**
45	 * Place modules on a single roof face on a regular grid.
46	 * Steps:
47	 *   1. Build a local frame on the face (normal = z, plus tangent + bitangent).
48	 *   2. Project the polygon vertices to 2D in that frame.
49	 *   3. Shrink the polygon by `EDGE_OFFSET_M` (per-edge inset).
50	 *   4. Tile a (W+gap) × (H+gap) grid across the polygon AABB.
51	 *   5. Keep cells whose center is inside the inset polygon AND outside every obstruction.
52	 *   6. Project each kept center back to world coords.
53	 */
54	export function placePanelsOnFace(
55	  face: RoofFace,
56	  obstructions: Obstruction[],
57	  maxModules?: number,
58	  shadeSampler?: ShadeSampler,
59	): ModulePosition[] {
60	  if (!face.vertices || face.vertices.length < 3) return [];
61	
62	  const normal = new THREE.Vector3().fromArray(face.normal).normalize();
63	  const origin = new THREE.Vector3().fromArray(face.vertices[0] as [number, number, number]);
64	
65	  // Pick a stable tangent: take an edge of the polygon, project it onto the face plane.
66	  const edgeWorld = new THREE.Vector3()
67	    .fromArray(face.vertices[1] as [number, number, number])
68	    .sub(origin);
69	  const tangent = edgeWorld.clone().sub(normal.clone().multiplyScalar(edgeWorld.dot(normal))).normalize();
70	  const bitangent = new THREE.Vector3().crossVectors(normal, tangent).normalize();
71	
72	  // World → local 2D
73	  const toLocal = (p: number[]): { u: number; v: number } => {
74	    const w = new THREE.Vector3().fromArray(p as [number, number, number]).sub(origin);
75	    return { u: w.dot(tangent), v: w.dot(bitangent) };
76	  };
77	  const toWorld = (u: number, v: number): THREE.Vector3 =>
78	    origin
79	      .clone()
80	      .add(tangent.clone().multiplyScalar(u))
81	      .add(bitangent.clone().multiplyScalar(v));
82	
83	  const polygon2D = face.vertices.map(toLocal);
84	
85	  // Polygon AABB in local frame.
86	  let minU = Infinity;
87	  let maxU = -Infinity;
88	  let minV = Infinity;
89	  let maxV = -Infinity;
90	  for (const { u, v } of polygon2D) {
91	    if (u < minU) minU = u;
92	    if (u > maxU) maxU = u;
93	    if (v < minV) minV = v;
94	    if (v > maxV) maxV = v;
95	  }
96	
97	  const stepU = MODULE_WIDTH_M + MODULE_GAP_M;
98	  const stepV = MODULE_HEIGHT_M + MODULE_GAP_M;
99	  const startU = minU + EDGE_OFFSET_M + MODULE_WIDTH_M / 2;
100	  const startV = minV + EDGE_OFFSET_M + MODULE_HEIGHT_M / 2;
101	  const endU = maxU - EDGE_OFFSET_M - MODULE_WIDTH_M / 2;
102	  const endV = maxV - EDGE_OFFSET_M - MODULE_HEIGHT_M / 2;
103	
104	  // Pre-project obstructions to local 2D (sphere projected onto face plane → disc).
105	  const obstructions2D = obstructions.map((o) => {
106	    const w = new THREE.Vector3().fromArray(o.position).sub(origin);
107	    return { u: w.dot(tangent), v: w.dot(bitangent), r: o.radius + 0.2 };
108	  });
109	
110	  const candidates: { u: number; v: number; yieldScore: number }[] = [];
111	  for (let u = startU; u <= endU + 1e-6; u += stepU) {
112	    for (let v = startV; v <= endV + 1e-6; v += stepV) {
113	      if (!isInsetInside(polygon2D, u, v, EDGE_OFFSET_M)) continue;
114	      if (obstructions2D.some((o) => Math.hypot(o.u - u, o.v - v) < o.r)) continue;
115	      if (shadeSampler) {
116	        const w = toWorld(u, v);
117	        if (shadeSampler.shadedFraction(w.x, w.y, w.z) > MAX_SHADED_FRACTION) continue;
118	      }
119	      // Higher v == closer to ridge → slightly higher yield (cheap heuristic).
120	      const yieldScore = v;
121	      candidates.push({ u, v, yieldScore });
122	    }
123	  }
124	
125	  candidates.sort((a, b) => b.yieldScore - a.yieldScore);
126	  const kept = typeof maxModules === 'number' ? candidates.slice(0, maxModules) : candidates;
127	
128	  return kept.map(({ u, v }) => {
129	    const w = toWorld(u, v);
130	    return { x: w.x, y: w.y, z: w.z, faceId: face.id };
131	  });
132	}
133	
134	/**
135	 * Point-in-polygon (ray casting) with a uniform inset.
136	 * The inset is approximate: we test the point AND the four corners of the
137	 * module footprint against the original polygon. Good enough for hackathon.
138	 */
139	function isInsetInside(
140	  polygon: { u: number; v: number }[],
141	  u: number,
142	  v: number,
143	  inset: number,
144	): boolean {
145	  const halfW = MODULE_WIDTH_M / 2 + inset;
146	  const halfH = MODULE_HEIGHT_M / 2 + inset;
147	  const corners = [
148	    { u, v },
149	    { u: u - halfW, v: v - halfH },
150	    { u: u + halfW, v: v - halfH },
151	    { u: u - halfW, v: v + halfH },
152	    { u: u + halfW, v: v + halfH },
153	  ];
154	  return corners.every((c) => pointInPolygon(polygon, c.u, c.v));
155	}
156	
157	function pointInPolygon(polygon: { u: number; v: number }[], u: number, v: number): boolean {
158	  let inside = false;
159	  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
160	    const pi = polygon[i];
161	    const pj = polygon[j];
162	    const intersect =
163	      pi.v > v !== pj.v > v &&
164	      u < ((pj.u - pi.u) * (v - pi.v)) / (pj.v - pi.v) + pi.u;
165	    if (intersect) inside = !inside;
166	  }
167	  return inside;
168	}

